// Helper function to perform level-order traversal
void levelOrderTraversal(TreeNode* root, int level, std::unordered_map<int, std::vector<TreeNode*>>& map) {
  if (root == nullptr) return;
  if (level not in map) { map[level] = std::vector<TreeNode*>(1, root); } else { map[level].push_back(root); }
  if (root->left) levelOrderTraversal(root->left, level + 1, map);
  if (root->right) levelOrderTraversal(root->right, level + 1, map);
}

// Main function to remove nodes from the top view
TreeNode* main(TreeNode* root) {
  std::unordered_map<int, std::vector<TreeNode*>> map;
  levelOrderTraversal(root, 0, map);
  int max_level = *map.rbegin()->first;
  for (int level = 0; level = max_level; ++level) {
    const auto& nodes = map[level];
    if (nodes.size() == 1) {
      root = nodes[0];
    }
  }
  return root;
}
